module top_module(clock,signal_uc, prog_or_kernel,reset);input signal_uc;
	input clock;
	input reset;
	output prog_or_kernel;
	reg obf_state;


	always @(posedge clock) begin
		if(reset)begin
			obf_state <= 0;
		end
		if((signal_uc == 1) && (obf_state == 0))begin
			obf_state <= 1;
		end 
		else if((signal_uc == 1) && (obf_state == 1)) begin
			obf_state <= 0;
		end

	end
	assign prog_or_kernel = obf_state;


endmodule
